{"code":"from decimal import Decimal

def migrate(input_record: str) -> str:
    rec = (input_record or "").ljust(21)[:21]

    def to_int(s: str) -> int:
        s = s.strip()
        return int(s) if s else 0

    def to_amount(s: str) -> Decimal:
        s = s.strip()
        if not s:
            return Decimal('0.00')
        return Decimal(int(s)) / Decimal('100')

    age = to_int(rec[6:9])
    plan_code = rec[9:10]
    service_days = to_int(rec[10:13])
    preauth_flag = rec[13:14]
    claim_amount = to_amount(rec[14:21])

    decision = 'A'
    reason = 'OK'

    if age < 18:
        decision = 'D'
        reason = 'A1'
    elif plan_code == 'B' and claim_amount > Decimal('1500.00'):
        decision = 'R'
        reason = 'B2'
    elif preauth_flag == 'N' and claim_amount > Decimal('1000.00'):
        decision = 'D'
        reason = 'P1'
    elif service_days > 30:
        decision = 'R'
        reason = 'L1'

    return f"{decision}{reason}"
"}

{"code":"from decimal import Decimal, ROUND_HALF_UP

def migrate(input_record: str) -> str:
    record = (input_record or "")[:44].ljust(44)

    def parse_int(s: str) -> int:
        s = s.strip()
        return int(s) if s else 0

    def parse_money(s: str) -> Decimal:
        s = s.strip()
        if not s:
            return Decimal('0')
        return Decimal(s) / Decimal('100')

    item_count = parse_int(record[6:8])
    if item_count < 0:
        item_count = 0
    if item_count > 4:
        item_count = 4

    total = Decimal('0')
    base = 8
    stride = 9

    for idx in range(item_count):
        off = base + idx * stride
        qty = parse_int(record[off:off + 2])
        price = parse_money(record[off + 2:off + 8])
        taxable = record[off + 8:off + 9]

        line_amount = (Decimal(qty) * price).quantize(Decimal('0.01'), rounding=ROUND_HALF_UP)
        if taxable == 'Y':
            line_amount = (line_amount * Decimal('1.075')).quantize(Decimal('0.01'), rounding=ROUND_HALF_UP)
        total += line_amount

    cents = int(total.quantize(Decimal('0.01'), rounding=ROUND_HALF_UP) * 100)
    return f"{cents:018d}"
"}
